import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppMode, AspectRatio, ImageSize, LoadingState, BatchImageItem } from './types';
import { editCarImage, generateCarImage, analyzeCarImage } from './services/geminiService';
import { fileToBase64, downloadResizedImage, downloadAllBatchImages } from './utils';
import { Button } from './components/Button';

// Icons as simple SVGs
const UploadIcon = () => (
  <svg className="w-8 h-8 mb-3 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
);
const CarIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 19H5V8h14m-3-5v2.206l-1.6 2.4h-6.8L6 5.206V3h12zM7 15a2 2 0 100 4 2 2 0 000-4zm10 0a2 2 0 100 4 2 2 0 000-4z" /></svg>
);
const SparkIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 3.214L13 21l-2.286-6.857L5 12l5.714-3.214z" /></svg>
);
const CloseIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
);
const DownloadIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
);

// Prompts for Shadow Editing
const PROMPT_A_MIRROR = "The vehicle pictured in the source image now rests on a highly polished, glossy white studio floor. Below the vehicle is a realistic, soft contact shadow, darkest and sharpest immediately under the tires and lower chassis to anchor it to the ground, and diffusing gently outwards. Furthermore, there are sharp, realistic reflections of the vehicle's body and wheels visible on the glossy surface. All other elements from the original source image, including the entire background environment, original lighting, and any text or graphics present in the frame, remain unchanged.";

const PROMPT_B_DARK = "Based strictly on image, the vehicle pictured now casts a realistic, soft contact shadow on the surface directly beneath it. This shadow is darkest immediately under the tires and chassis to anchor the car to the ground, and fades gently outwards. All other elements of image, including the vehicle's specific appearance, the entire background environment, original lighting, reflections, and any text or graphics present in the frame, remain absolutely identical to the original source image.";

const PROMPT_REMOVE_BACKGROUND = "Remove the background from the car image, making it transparent.";


const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.EDIT_SHADOW);
  // Single image states (for EDIT_SHADOW, TEXT_EDIT, GENERATE, ANALYZE modes)
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [originalDims, setOriginalDims] = useState<{w: number, h: number} | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [resultText, setResultText] = useState<string | null>(null);

  // Batch image states (for BATCH_EDIT_SHADOW mode)
  const [selectedBatchItems, setSelectedBatchItems] = useState<BatchImageItem[]>([]);
  const [resultBatchItems, setResultBatchItems] = useState<BatchImageItem[]>([]);

  // Settings
  const [prompt, setPrompt] = useState<string>(""); // Used for TEXT_EDIT, GENERATE and ANALYZE
  const [genAspectRatio, setGenAspectRatio] = useState<AspectRatio>(AspectRatio.LANDSCAPE_16_9);
  const [genImageSize, setGenImageSize] = useState<ImageSize>(ImageSize.SIZE_2K);

  const [loading, setLoading] = useState<LoadingState>({ isLoading: false, message: '' });
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const batchFileInputRef = useRef<HTMLInputElement>(null);

  // Handle PWA Install Prompt
  useEffect(() => {
    const handler = (e: any) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handler);

    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (!installPrompt) return;

    // Show the install prompt
    installPrompt.prompt();

    // Wait for the user to respond to the prompt
    installPrompt.userChoice.then((choiceResult: any) => {
      if (choiceResult.outcome === 'accepted') {
        console.log('User accepted the install prompt');
        setInstallPrompt(null);
      } else {
        console.log('User dismissed the install prompt');
      }
    });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>, isBatch: boolean = false) => {
    if (!event.target.files) return;

    const files = Array.from(event.target.files) as File[];

    if (isBatch) {
      const newItems: BatchImageItem[] = [];
      const currentCount = selectedBatchItems.length;
      const maxBatchSize = 6;

      for (let i = 0; i < files.length && currentCount + i < maxBatchSize; i++) {
        const file = files[i];
        const id = `${file.name}-${Date.now()}-${i}`;
        const url = URL.createObjectURL(file);

        const img = new Image();
        img.onload = () => {
          setSelectedBatchItems(prev => prev.map(item => 
            item.id === id ? { ...item, originalDims: { w: img.width, h: img.height } } : item
          ));
        };
        img.src = url;

        newItems.push({ id, file, previewUrl: url, originalDims: null, loading: false });
      }
      setSelectedBatchItems(prev => [...prev, ...newItems]);
      setResultBatchItems([]); // Clear previous batch results
    } else {
      const file = files[0];
      setSelectedFile(file);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
      setResultImage(null);
      setResultText(null);

      const img = new Image();
      img.onload = () => {
        setOriginalDims({ w: img.width, h: img.height });
      };
      img.src = url;
    }
    // Clear the input value so the same file can be selected again
    if (event.target) {
      event.target.value = '';
    }
  };

  const handleRemoveImage = useCallback((e: React.MouseEvent, isBatch: boolean = false, itemId?: string) => {
    e.stopPropagation();
    if (isBatch && itemId) {
      setSelectedBatchItems(prev => prev.filter(item => item.id !== itemId));
      setResultBatchItems(prev => prev.filter(item => item.id !== itemId));
    } else {
      setSelectedFile(null);
      setPreviewUrl(null);
      setOriginalDims(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  }, []);

  const handleAction = async (specificPrompt?: string) => {
    setLoading({ isLoading: true, message: 'Procesando con Gemini AI...' });
    setResultImage(null);
    setResultText(null);
    setResultBatchItems([]); // Clear batch results before new processing

    const promptToUse = specificPrompt || prompt;

    try {
      if (mode === AppMode.EDIT_SHADOW || mode === AppMode.TEXT_EDIT) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const editedImage = await editCarImage(base64, promptToUse, selectedFile.type);
        setResultImage(editedImage);
      } else if (mode === AppMode.GENERATE) {
        const generated = await generateCarImage(promptToUse, genAspectRatio, genImageSize);
        setResultImage(generated);
      } else if (mode === AppMode.ANALYZE) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const analysis = await analyzeCarImage(base64, promptToUse || "Analiza este vehículo: marca, modelo estimado, color y características visibles.", selectedFile.type);
        setResultText(analysis);
      } else if (mode === AppMode.BATCH_EDIT_SHADOW) {
        if (selectedBatchItems.length === 0) throw new Error("Selecciona al menos una imagen para el procesamiento por lotes.");

        const processedResults: BatchImageItem[] = await Promise.all(selectedBatchItems.map(async (item) => {
          setSelectedBatchItems(prev => prev.map(i => i.id === item.id ? { ...i, loading: true, errorMessage: undefined } : i));
          try {
            const base64 = await fileToBase64(item.file);
            const editedImage = await editCarImage(base64, promptToUse, item.file.type);
            return { ...item, resultImage: editedImage, loading: false, errorMessage: undefined };
          } catch (error) {
            console.error(`Error processing batch item ${item.id}:`, error);
            return { ...item, resultImage: null, loading: false, errorMessage: "Error procesando imagen" };
          }
        }));
        setResultBatchItems(processedResults);
        // Clear loading states from selectedBatchItems as results are in resultBatchItems
        setSelectedBatchItems(prev => prev.map(item => ({ ...item, loading: false })));
      }
    } catch (error) {
      console.error(error);
      alert("Hubo un error procesando tu solicitud. Por favor intenta de nuevo.");
    } finally {
      setLoading({ isLoading: false, message: '' });
    }
  };

  const resetState = useCallback((newMode: AppMode) => {
    setMode(newMode);
    setResultImage(null);
    setResultText(null);
    setSelectedFile(null);
    setPreviewUrl(null);
    setOriginalDims(null);
    setSelectedBatchItems([]);
    setResultBatchItems([]);
    if (fileInputRef.current) fileInputRef.current.value = '';
    if (batchFileInputRef.current) batchFileInputRef.current.value = '';

    // Set default prompts based on mode
    if (newMode === AppMode.GENERATE) {
      setPrompt("Un auto deportivo futurista color plata conduciendo bajo la lluvia en una ciudad cyberpunk neon.");
    } else if (newMode === AppMode.ANALYZE) {
      setPrompt("Analiza este vehículo: marca, modelo estimado, y estilo.");
    } else if (newMode === AppMode.TEXT_EDIT) {
      setPrompt("Añade un filtro retro a la imagen, o quita a la persona del fondo.");
    }
    else {
      setPrompt(""); // Clear prompt for modes that use buttons or no prompt
    }
  }, []); // Empty dependency array means this function is created once

  const hasSuccessfulBatchResults = resultBatchItems.some(item => item.resultImage);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-blue-500/30">
      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg">
              <CarIcon />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-400">
              AutoShadow AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
            {installPrompt && (
              <button
                onClick={handleInstallClick}
                className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-medium rounded-full border border-slate-700 transition-colors"
              >
                <DownloadIcon />
                Instalar App
              </button>
            )}
            <div className="text-xs text-slate-500 font-mono hidden sm:block">
              Powered by Gemini 2.5 & 3.0
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Navigation Tabs */}
        <div className="flex flex-wrap gap-2 mb-8 p-1 bg-slate-900/80 rounded-xl border border-slate-800 w-full md:w-fit">
          <button
            onClick={() => resetState(AppMode.EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.EDIT_SHADOW ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Editar & Sombras
          </button>
          <button
            onClick={() => resetState(AppMode.TEXT_EDIT)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.TEXT_EDIT ? 'bg-amber-600 text-white shadow-lg shadow-amber-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Edición Libre
          </button>
          <button
            onClick={() => resetState(AppMode.BATCH_EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.BATCH_EDIT_SHADOW ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Lotes
          </button>
          <button
            onClick={() => resetState(AppMode.GENERATE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.GENERATE ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Generar Nuevo
          </button>
          <button
            onClick={() => resetState(AppMode.ANALYZE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.ANALYZE ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Analizar
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Controls Column */}
          <div className="lg:col-span-4 space-y-6">

            {/* Image Upload Area (for single image modes) */}
            {(mode === AppMode.EDIT_SHADOW || mode === AppMode.ANALYZE || mode === AppMode.TEXT_EDIT) && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imagen Original</h2>
                <div 
                  className={`border-2 border-dashed rounded-xl h-48 flex flex-col items-center justify-center cursor-pointer transition-colors ${previewUrl ? 'border-slate-600 bg-slate-800/50' : 'border-slate-700 hover:border-blue-500 hover:bg-slate-800/50'}`}
                  onClick={() => fileInputRef.current?.click()}
                  style={previewUrl ? { backgroundImage: `url(${previewUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' } : {}}
                >
                  {!previewUrl && (
                    <>
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Click para subir auto</p>
                      <p className="text-xs text-slate-500 mt-1">JPG, PNG</p>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*" 
                    onChange={(e) => handleFileChange(e, false)} 
                  />
                </div>
                {previewUrl && (
                  <button 
                    onClick={(e) => handleRemoveImage(e, false)}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover imagen
                  </button>
                )}
                {originalDims && (
                  <p className="text-xs text-slate-600 mt-2 text-center">
                    Dimensiones: {originalDims.w} x {originalDims.h} px
                  </p>
                )}
              </div>
            )}

            {/* Batch Image Upload Area */}
            {mode === AppMode.BATCH_EDIT_SHADOW && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imágenes Originales (Lotes)</h2>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {selectedBatchItems.map(item => (
                    <div key={item.id} className="relative w-full h-32 rounded-xl border border-slate-700 bg-slate-800/50 overflow-hidden group">
                      <img src={item.previewUrl} alt="Preview" className="w-full h-full object-cover" />
                      <button 
                        onClick={(e) => handleRemoveImage(e, true, item.id)}
                        className="absolute top-1 right-1 bg-red-600 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                        aria-label="Remover imagen"
                      >
                        <CloseIcon />
                      </button>
                      {item.originalDims && (
                        <p className="absolute bottom-1 left-1 text-white text-[10px] bg-black/50 px-1 rounded">
                          {item.originalDims.w}x{item.originalDims.h}
                        </p>
                      )}
                    </div>
                  ))}
                  {selectedBatchItems.length < 6 && (
                    <div 
                      className="border-2 border-dashed rounded-xl h-32 flex flex-col items-center justify-center cursor-pointer transition-colors border-slate-700 hover:border-blue-500 hover:bg-slate-800/50"
                      onClick={() => batchFileInputRef.current?.click()}
                    >
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Agregar ({6 - selectedBatchItems.length})</p>
                      <input 
                        type="file" 
                        ref={batchFileInputRef} 
                        className="hidden" 
                        accept="image/*" 
                        multiple
                        onChange={(e) => handleFileChange(e, true)} 
                      />
                    </div>
                  )}
                </div>
                 {selectedBatchItems.length > 0 && (
                  <button 
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedBatchItems([]);
                      setResultBatchItems([]);
                      if (batchFileInputRef.current) batchFileInputRef.current.value = '';
                    }}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover todas las imágenes
                  </button>
                )}
              </div>
            )}


            {/* Prompt & Settings Area */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl space-y-4">
              <h2 className="text-lg font-semibold text-white">Configuración</h2>

              {/* Prompt Input - Shown for TEXT_EDIT, Generate and Analyze modes */}
              {(mode === AppMode.GENERATE || mode === AppMode.ANALYZE || mode === AppMode.TEXT_EDIT) && (
                <div className="space-y-2">
                  <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">
                    Prompt (Instrucción)
                  </label>
                  <textarea
                    className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-sm text-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none resize-none h-32"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe lo que quieres hacer..."
                  />
                </div>
              )}

              {mode === AppMode.GENERATE && (
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Relación Aspecto</label>
                    <select 
                      value={genAspectRatio}
                      onChange={(e) => setGenAspectRatio(e.target.value as AspectRatio)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(AspectRatio).map(ratio => (
                        <option key={ratio} value={ratio}>{ratio}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Resolución</label>
                    <select 
                      value={genImageSize}
                      onChange={(e) => setGenImageSize(e.target.value as ImageSize)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(ImageSize).map(size => (
                        <option key={size} value={size}>{size}</option>
                      ))}
                    </select>
                  </div>
                </div>
              )}

              {/* Action Buttons */}
              {(mode === AppMode.EDIT_SHADOW || mode === AppMode.BATCH_EDIT_SHADOW || mode === AppMode.TEXT_EDIT) ? (
                <div className="space-y-3 mt-4">
                  <Button 
                    onClick={() => handleAction(PROMPT_A_MIRROR)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/50"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Espejo
                  </Button>
                  <Button 
                    onClick={() => handleAction(PROMPT_B_DARK)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-slate-700 hover:bg-slate-600 text-slate-100 border border-slate-600"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Oscura
                  </Button>
                  {(mode === AppMode.EDIT_SHADOW || mode === AppMode.TEXT_EDIT || mode === AppMode.BATCH_EDIT_SHADOW) && (
                    <Button 
                      onClick={() => handleAction(PROMPT_REMOVE_BACKGROUND)} 
                      isLoading={loading.isLoading}
                      variant="secondary"
                      className="w-full border-dashed border-slate-600"
                      disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                    >
                      {!loading.isLoading && <SparkIcon />}
                      Remover Fondo
                    </Button>
                  )}
                </div>
              ) : (
                <Button 
                  onClick={() => handleAction()} 
                  isLoading={loading.isLoading}
                  className="w-full mt-4"
                  disabled={!selectedFile && mode !== AppMode.GENERATE} // Disable if no file for Edit/Analyze/TextEdit, but not for Generate
                >
                  {!loading.isLoading && <SparkIcon />}
                  {loading.isLoading ? loading.message : 
                   mode === AppMode.ANALYZE ? 'Analizar' : 
                   mode === AppMode.TEXT_EDIT ? 'Editar Imagen' : 
                   'Generar'}
                </Button>
              )}
            </div>
          </div>

          {/* Result Column */}
          <div className="lg:col-span-8">
            <div className="bg-slate-900 rounded-2xl border border-slate-800 shadow-xl h-full min-h-[500px] flex flex-col overflow-hidden relative">
              <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50">
                <h2 className="text-lg font-semibold text-white">Resultado</h2>
                {(resultImage || resultBatchItems.length > 0) && (
                  <div className="flex gap-2">
                    {/* For single image mode */}
                    {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && ( // Ensure it's not batch mode
                      <>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.png`, 'image/png', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3"
                        >
                          Descargar PNG
                        </Button>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.jpg`, 'image/jpeg', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3 bg-slate-800"
                        >
                          Descargar JPG
                        </Button>
                      </>
                    )}
                    {/* Batch mode global download */}
                    {mode === AppMode.BATCH_EDIT_SHADOW && hasSuccessfulBatchResults && (
                      <Button
                        variant="primary"
                        onClick={() => downloadAllBatchImages(resultBatchItems)}
                        isLoading={loading.isLoading}
                        className="text-xs py-1.5 px-3"
                      >
                        Descargar Todo (Zip)
                      </Button>
                    )}
                  </div>
                )}
              </div>

              <div className="flex-1 bg-slate-950 flex items-center justify-center p-4 relative">

                {/* Empty State */}
                {!resultImage && !resultText && !loading.isLoading && resultBatchItems.length === 0 && (
                  <div className="text-center text-slate-600 max-w-sm">
                    <div className="mx-auto w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4 border border-slate-800">
                      <SparkIcon />
                    </div>
                    <p className="text-lg font-medium text-slate-500">Listo para crear magia</p>
                    {mode === AppMode.BATCH_EDIT_SHADOW ? (
                      <p className="text-sm mt-2">Sube hasta 6 imágenes para procesar por lotes.</p>
                    ) : mode === AppMode.TEXT_EDIT ? (
                      <p className="text-sm mt-2">Sube una imagen y describe el cambio que quieres hacer.</p>
                    ) : (
                      <p className="text-sm mt-2">Sube una imagen o selecciona un tipo de sombra.</p>
                    )}
                  </div>
                )}

                {/* Loading State */}
                {loading.isLoading && (
                  <div className="absolute inset-0 z-10 bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center">
                    <div className="w-16 h-16 border-4 border-blue-600/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                    <p className="text-blue-400 animate-pulse">{loading.message}</p>
                    {mode === AppMode.GENERATE && genImageSize === ImageSize.SIZE_4K && (
                      <p className="text-xs text-slate-500 mt-2">Generar en 4K puede tomar un momento...</p>
                    )}
                  </div>
                )}

                {/* Single Image Result */}
                {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && (
                  <img 
                    src={resultImage} 
                    alt="Result" 
                    className="max-w-full max-h-[70vh] rounded-lg shadow-2xl object-contain border border-slate-800"
                  />
                )}

                {/* Batch Image Results */}
                {mode === AppMode.BATCH_EDIT_SHADOW && resultBatchItems.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-h-[70vh] overflow-y-auto p-2">
                    {resultBatchItems.map(item => (
                      <div key={item.id} className="bg-slate-900 rounded-lg p-3 border border-slate-800 flex flex-col items-center space-y-2 shadow-lg">
                        {item.loading && (
                           <div className="w-full h-48 bg-slate-800 flex items-center justify-center rounded-md">
                             <div className="w-10 h-10 border-2 border-blue-600/30 border-t-blue-500 rounded-full animate-spin"></div>
                           </div>
                        )}
                        {item.errorMessage && !item.loading && (
                          <div className="w-full h-48 bg-red-900/30 text-red-400 flex items-center justify-center rounded-md text-sm">
                            {item.errorMessage}
                          </div>
                        )}
                        {item.resultImage && !item.loading && (
                          <img 
                            src={item.resultImage} 
                            alt={`Result for ${item.file.name}`} 
                            className="max-w-full h-48 object-contain rounded-md border border-slate-700"
                          />
                        )}
                        <p className="text-xs text-slate-400 truncate w-full text-center">
                           Original: {item.file.name} ({item.originalDims?.w}x{item.originalDims?.h}px)
                        </p>
                        {item.resultImage && (
                           <div className="flex gap-2 mt-2">
                             <Button 
                               variant="secondary" 
                               onClick={() => downloadResizedImage(item.resultImage!, `autoshadow-${item.id}.png`, 'image/png', item.originalDims?.w, item.originalDims?.h)}
                               className="text-xs py-1.5 px-3"
                             >
                               Descargar PNG
                             </Button>
                             <Button 
                               variant="secondary" 
                               onClick={() => downloadResizedImage(item.resultImage!, `autoshadow-${item.id}.jpg`, 'image/jpeg', item.originalDims?.w, item.originalDims?.h)}
                               className="text-xs py-1.5 px-3 bg-slate-800"
                             >
                               Descargar JPG
                             </Button>
                           </div>
                        )}
                      </div>
                    ))}
                  </div>
                )}

                {/* Text Analysis Result */}
                {resultText && (
                  <div className="w-full max-w-2xl bg-slate-900 p-6 rounded-xl border border-slate-800 overflow-y-auto max-h-[70vh]">
                    <h3 className="text-xl font-bold text-emerald-400 mb-4 flex items-center gap-2">
                      <span className="bg-emerald-500/10 p-1 rounded">✨</span> Análisis de Vehículo
                    </h3>
                    <div className="prose prose-invert prose-slate max-w-none whitespace-pre-wrap leading-relaxed">
                      {resultText}
                    </div>
                    <div className="mt-8 pt-4 border-t border-slate-800 text-xs text-slate-500 text-center">
                      Nota: Este análisis es generado por IA y puede contener imprecisiones sobre especificaciones técnicas exactas.
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppMode, AspectRatio, ImageSize, LoadingState, BatchImageItem } from './types';
import { editCarImage, generateCarImage, analyzeCarImage } from './services/geminiService';
import { fileToBase64, downloadResizedImage, downloadAllBatchImages } from './utils';
import { Button } from './components/Button';

// Icons as simple SVGs
const UploadIcon = () => (
  <svg className="w-8 h-8 mb-3 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
);
const CarIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 19H5V8h14m-3-5v2.206l-1.6 2.4h-6.8L6 5.206V3h12zM7 15a2 2 0 100 4 2 2 0 000-4zm10 0a2 2 0 100 4 2 2 0 000-4z" /></svg>
);
const SparkIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 3.214L13 21l-2.286-6.857L5 12l5.714-3.214z" /></svg>
);
const CloseIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
);
const DownloadIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
);

// Prompts for Shadow Editing
const PROMPT_A_MIRROR = "The vehicle pictured in the source image now rests on a highly polished, glossy white studio floor. Below the vehicle is a realistic, soft contact shadow, darkest and sharpest immediately under the tires and lower chassis to anchor it to the ground, and diffusing gently outwards. Furthermore, there are sharp, realistic reflections of the vehicle's body and wheels visible on the glossy surface. All other elements from the original source image, including the entire background environment, original lighting, and any text or graphics present in the frame, remain unchanged.";

const PROMPT_B_DARK = "Based strictly on image, the vehicle pictured now casts a realistic, soft contact shadow on the surface directly beneath it. This shadow is darkest immediately under the tires and chassis to anchor the car to the ground, and fades gently outwards. All other elements of image, including the vehicle's specific appearance, the entire background environment, original lighting, reflections, and any text or graphics present in the frame, remain absolutely identical to the original source image.";


const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.EDIT_SHADOW);
  // Single image states (for EDIT_SHADOW, TEXT_EDIT, GENERATE, ANALYZE modes)
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [originalDims, setOriginalDims] = useState<{w: number, h: number} | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [resultText, setResultText] = useState<string | null>(null);

  // Batch image states (for BATCH_EDIT_SHADOW mode)
  const [selectedBatchItems, setSelectedBatchItems] = useState<BatchImageItem[]>([]);
  const [resultBatchItems, setResultBatchItems] = useState<BatchImageItem[]>([]);

  // Settings
  const [prompt, setPrompt] = useState<string>(""); // Used for TEXT_EDIT, GENERATE and ANALYZE
  const [genAspectRatio, setGenAspectRatio] = useState<AspectRatio>(AspectRatio.LANDSCAPE_16_9);
  const [genImageSize, setGenImageSize] = useState<ImageSize>(ImageSize.SIZE_2K);

  const [loading, setLoading] = useState<LoadingState>({ isLoading: false, message: '' });
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const batchFileInputRef = useRef<HTMLInputElement>(null);

  // Handle PWA Install Prompt
  useEffect(() => {
    const handler = (e: any) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handler);

    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (!installPrompt) return;

    // Show the install prompt
    installPrompt.prompt();

    // Wait for the user to respond to the prompt
    installPrompt.userChoice.then((choiceResult: any) => {
      if (choiceResult.outcome === 'accepted') {
        console.log('User accepted the install prompt');
        setInstallPrompt(null);
      } else {
        console.log('User dismissed the install prompt');
      }
    });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>, isBatch: boolean = false) => {
    if (!event.target.files) return;

    const files = Array.from(event.target.files) as File[];

    if (isBatch) {
      const newItems: BatchImageItem[] = [];
      const currentCount = selectedBatchItems.length;
      const maxBatchSize = 6;

      for (let i = 0; i < files.length && currentCount + i < maxBatchSize; i++) {
        const file = files[i];
        const id = `${file.name}-${Date.now()}-${i}`;
        const url = URL.createObjectURL(file);

        const img = new Image();
        img.onload = () => {
          setSelectedBatchItems(prev => prev.map(item => 
            item.id === id ? { ...item, originalDims: { w: img.width, h: img.height } } : item
          ));
        };
        img.src = url;

        newItems.push({ id, file, previewUrl: url, originalDims: null, loading: false });
      }
      setSelectedBatchItems(prev => [...prev, ...newItems]);
      setResultBatchItems([]); // Clear previous batch results
    } else {
      const file = files[0];
      setSelectedFile(file);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
      setResultImage(null);
      setResultText(null);

      const img = new Image();
      img.onload = () => {
        setOriginalDims({ w: img.width, h: img.height });
      };
      img.src = url;
    }
    // Clear the input value so the same file can be selected again
    if (event.target) {
      event.target.value = '';
    }
  };

  const handleRemoveImage = useCallback((e: React.MouseEvent, isBatch: boolean = false, itemId?: string) => {
    e.stopPropagation();
    if (isBatch && itemId) {
      setSelectedBatchItems(prev => prev.filter(item => item.id !== itemId));
      setResultBatchItems(prev => prev.filter(item => item.id !== itemId));
    } else {
      setSelectedFile(null);
      setPreviewUrl(null);
      setOriginalDims(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  }, []);

  const handleAction = async (specificPrompt?: string) => {
    setLoading({ isLoading: true, message: 'Procesando con Gemini AI...' });
    setResultImage(null);
    setResultText(null);
    setResultBatchItems([]); // Clear batch results before new processing

    const promptToUse = specificPrompt || prompt;

    try {
      if (mode === AppMode.EDIT_SHADOW || mode === AppMode.TEXT_EDIT) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const editedImage = await editCarImage(base64, promptToUse, selectedFile.type);
        setResultImage(editedImage);
      } else if (mode === AppMode.GENERATE) {
        const generated = await generateCarImage(promptToUse, genAspectRatio, genImageSize);
        setResultImage(generated);
      } else if (mode === AppMode.ANALYZE) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const analysis = await analyzeCarImage(base64, promptToUse || "Analiza este vehículo: marca, modelo estimado, color y características visibles.", selectedFile.type);
        setResultText(analysis);
      } else if (mode === AppMode.BATCH_EDIT_SHADOW) {
        if (selectedBatchItems.length === 0) throw new Error("Selecciona al menos una imagen para el procesamiento por lotes.");

        const processedResults: BatchImageItem[] = await Promise.all(selectedBatchItems.map(async (item) => {
          setSelectedBatchItems(prev => prev.map(i => i.id === item.id ? { ...i, loading: true, errorMessage: undefined } : i));
          try {
            const base64 = await fileToBase64(item.file);
            const editedImage = await editCarImage(base64, promptToUse, item.file.type);
            return { ...item, resultImage: editedImage, loading: false, errorMessage: undefined };
          } catch (error) {
            console.error(`Error processing batch item ${item.id}:`, error);
            return { ...item, resultImage: null, loading: false, errorMessage: "Error procesando imagen" };
          }
        }));
        setResultBatchItems(processedResults);
        // Clear loading states from selectedBatchItems as results are in resultBatchItems
        setSelectedBatchItems(prev => prev.map(item => ({ ...item, loading: false })));
      }
    } catch (error) {
      console.error(error);
      alert("Hubo un error procesando tu solicitud. Por favor intenta de nuevo.");
    } finally {
      setLoading({ isLoading: false, message: '' });
    }
  };

  const resetState = useCallback((newMode: AppMode) => {
    setMode(newMode);
    setResultImage(null);
    setResultText(null);
    setSelectedFile(null);
    setPreviewUrl(null);
    setOriginalDims(null);
    setSelectedBatchItems([]);
    setResultBatchItems([]);
    if (fileInputRef.current) fileInputRef.current.value = '';
    if (batchFileInputRef.current) batchFileInputRef.current.value = '';

    // Set default prompts based on mode
    if (newMode === AppMode.GENERATE) {
      setPrompt("Un auto deportivo futurista color plata conduciendo bajo la lluvia en una ciudad cyberpunk neon.");
    } else if (newMode === AppMode.ANALYZE) {
      setPrompt("Analiza este vehículo: marca, modelo estimado, y estilo.");
    } else if (newMode === AppMode.TEXT_EDIT) {
      setPrompt("Añade un filtro retro a la imagen, o quita a la persona del fondo.");
    }
    else {
      setPrompt(""); // Clear prompt for modes that use buttons or no prompt
    }
  }, []); // Empty dependency array means this function is created once

  const hasSuccessfulBatchResults = resultBatchItems.some(item => item.resultImage);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-blue-500/30">
      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg">
              <CarIcon />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-400">
              AutoShadow AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
            {installPrompt && (
              <button
                onClick={handleInstallClick}
                className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-medium rounded-full border border-slate-700 transition-colors"
              >
                <DownloadIcon />
                Instalar App
              </button>
            )}
            <div className="text-xs text-slate-500 font-mono hidden sm:block">
              Powered by Gemini 2.5 & 3.0
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Navigation Tabs */}
        <div className="flex flex-wrap gap-2 mb-8 p-1 bg-slate-900/80 rounded-xl border border-slate-800 w-full md:w-fit">
          <button
            onClick={() => resetState(AppMode.EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.EDIT_SHADOW ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Editar & Sombras
          </button>
          <button
            onClick={() => resetState(AppMode.TEXT_EDIT)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.TEXT_EDIT ? 'bg-amber-600 text-white shadow-lg shadow-amber-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Edición Libre
          </button>
          <button
            onClick={() => resetState(AppMode.BATCH_EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.BATCH_EDIT_SHADOW ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Lotes
          </button>
          <button
            onClick={() => resetState(AppMode.GENERATE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.GENERATE ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Generar Nuevo
          </button>
          <button
            onClick={() => resetState(AppMode.ANALYZE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.ANALYZE ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Analizar
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Controls Column */}
          <div className="lg:col-span-4 space-y-6">

            {/* Image Upload Area (for single image modes) */}
            {(mode === AppMode.EDIT_SHADOW || mode === AppMode.ANALYZE || mode === AppMode.TEXT_EDIT) && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imagen Original</h2>
                <div 
                  className={`border-2 border-dashed rounded-xl h-48 flex flex-col items-center justify-center cursor-pointer transition-colors ${previewUrl ? 'border-slate-600 bg-slate-800/50' : 'border-slate-700 hover:border-blue-500 hover:bg-slate-800/50'}`}
                  onClick={() => fileInputRef.current?.click()}
                  style={previewUrl ? { backgroundImage: `url(${previewUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' } : {}}
                >
                  {!previewUrl && (
                    <>
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Click para subir auto</p>
                      <p className="text-xs text-slate-500 mt-1">JPG, PNG</p>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*" 
                    onChange={(e) => handleFileChange(e, false)} 
                  />
                </div>
                {previewUrl && (
                  <button 
                    onClick={(e) => handleRemoveImage(e, false)}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover imagen
                  </button>
                )}
                {originalDims && (
                  <p className="text-xs text-slate-600 mt-2 text-center">
                    Dimensiones: {originalDims.w} x {originalDims.h} px
                  </p>
                )}
              </div>
            )}

            {/* Batch Image Upload Area */}
            {mode === AppMode.BATCH_EDIT_SHADOW && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imágenes Originales (Lotes)</h2>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {selectedBatchItems.map(item => (
                    <div key={item.id} className="relative w-full h-32 rounded-xl border border-slate-700 bg-slate-800/50 overflow-hidden group">
                      <img src={item.previewUrl} alt="Preview" className="w-full h-full object-cover" />
                      <button 
                        onClick={(e) => handleRemoveImage(e, true, item.id)}
                        className="absolute top-1 right-1 bg-red-600 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                        aria-label="Remover imagen"
                      >
                        <CloseIcon />
                      </button>
                      {item.originalDims && (
                        <p className="absolute bottom-1 left-1 text-white text-[10px] bg-black/50 px-1 rounded">
                          {item.originalDims.w}x{item.originalDims.h}
                        </p>
                      )}
                    </div>
                  ))}
                  {selectedBatchItems.length < 6 && (
                    <div 
                      className="border-2 border-dashed rounded-xl h-32 flex flex-col items-center justify-center cursor-pointer transition-colors border-slate-700 hover:border-blue-500 hover:bg-slate-800/50"
                      onClick={() => batchFileInputRef.current?.click()}
                    >
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Agregar ({6 - selectedBatchItems.length})</p>
                      <input 
                        type="file" 
                        ref={batchFileInputRef} 
                        className="hidden" 
                        accept="image/*" 
                        multiple
                        onChange={(e) => handleFileChange(e, true)} 
                      />
                    </div>
                  )}
                </div>
                 {selectedBatchItems.length > 0 && (
                  <button 
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedBatchItems([]);
                      setResultBatchItems([]);
                      if (batchFileInputRef.current) batchFileInputRef.current.value = '';
                    }}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover todas las imágenes
                  </button>
                )}
              </div>
            )}


            {/* Prompt & Settings Area */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl space-y-4">
              <h2 className="text-lg font-semibold text-white">Configuración</h2>

              {/* Prompt Input - Shown for TEXT_EDIT, Generate and Analyze modes */}
              {(mode === AppMode.GENERATE || mode === AppMode.ANALYZE || mode === AppMode.TEXT_EDIT) && (
                <div className="space-y-2">
                  <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">
                    Prompt (Instrucción)
                  </label>
                  <textarea
                    className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-sm text-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none resize-none h-32"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe lo que quieres hacer..."
                  />
                </div>
              )}

              {mode === AppMode.GENERATE && (
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Relación Aspecto</label>
                    <select 
                      value={genAspectRatio}
                      onChange={(e) => setGenAspectRatio(e.target.value as AspectRatio)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(AspectRatio).map(ratio => (
                        <option key={ratio} value={ratio}>{ratio}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Resolución</label>
                    <select 
                      value={genImageSize}
                      onChange={(e) => setGenImageSize(e.target.value as ImageSize)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(ImageSize).map(size => (
                        <option key={size} value={size}>{size}</option>
                      ))}
                    </select>
                  </div>
                </div>
              )}

              {/* Action Buttons */}
              {(mode === AppMode.EDIT_SHADOW || mode === AppMode.BATCH_EDIT_SHADOW || mode === AppMode.TEXT_EDIT) ? (
                <div className="space-y-3 mt-4">
                  <Button 
                    onClick={() => handleAction(PROMPT_A_MIRROR)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/50"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Espejo
                  </Button>
                  <Button 
                    onClick={() => handleAction(PROMPT_B_DARK)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-slate-700 hover:bg-slate-600 text-slate-100 border border-slate-600"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Oscura
                  </Button>
                </div>
              ) : (
                <Button 
                  onClick={() => handleAction()} 
                  isLoading={loading.isLoading}
                  className="w-full mt-4"
                  disabled={!selectedFile && mode !== AppMode.GENERATE} // Disable if no file for Edit/Analyze/TextEdit, but not for Generate
                >
                  {!loading.isLoading && <SparkIcon />}
                  {loading.isLoading ? loading.message : 
                   mode === AppMode.ANALYZE ? 'Analizar' : 
                   mode === AppMode.TEXT_EDIT ? 'Editar Imagen' : 
                   'Generar'}
                </Button>
              )}
            </div>
          </div>

          {/* Result Column */}
          <div className="lg:col-span-8">
            <div className="bg-slate-900 rounded-2xl border border-slate-800 shadow-xl h-full min-h-[500px] flex flex-col overflow-hidden relative">
              <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50">
                <h2 className="text-lg font-semibold text-white">Resultado</h2>
                {(resultImage || resultBatchItems.length > 0) && (
                  <div className="flex gap-2">
                    {/* For single image mode */}
                    {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && ( // Ensure it's not batch mode
                      <>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.png`, 'image/png', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3"
                        >
                          Descargar PNG
                        </Button>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.jpg`, 'image/jpeg', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3 bg-slate-800"
                        >
                          Descargar JPG
                        </Button>
                      </>
                    )}
                    {/* Batch mode global download */}
                    {mode === AppMode.BATCH_EDIT_SHADOW && hasSuccessfulBatchResults && (
                      <Button
                        variant="primary"
                        onClick={() => downloadAllBatchImages(resultBatchItems)}
                        isLoading={loading.isLoading}
                        className="text-xs py-1.5 px-3"
                      >
                        Descargar Todo (Zip)
                      </Button>
                    )}
                  </div>
                )}
              </div>

              <div className="flex-1 bg-slate-950 flex items-center justify-center p-4 relative">

                {/* Empty State */}
                {!resultImage && !resultText && !loading.isLoading && resultBatchItems.length === 0 && (
                  <div className="text-center text-slate-600 max-w-sm">
                    <div className="mx-auto w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4 border border-slate-800">
                      <SparkIcon />
                    </div>
                    <p className="text-lg font-medium text-slate-500">Listo para crear magia</p>
                    {mode === AppMode.BATCH_EDIT_SHADOW ? (
                      <p className="text-sm mt-2">Sube hasta 6 imágenes para procesar por lotes.</p>
                    ) : mode === AppMode.TEXT_EDIT ? (
                      <p className="text-sm mt-2">Sube una imagen y describe el cambio que quieres hacer.</p>
                    ) : (
                      <p className="text-sm mt-2">Sube una imagen o selecciona un tipo de sombra.</p>
                    )}
                  </div>
                )}

                {/* Loading State */}
                {loading.isLoading && (
                  <div className="absolute inset-0 z-10 bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center">
                    <div className="w-16 h-16 border-4 border-blue-600/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                    <p className="text-blue-400 animate-pulse">{loading.message}</p>
                    {mode === AppMode.GENERATE && genImageSize === ImageSize.SIZE_4K && (
                      <p className="text-xs text-slate-500 mt-2">Generar en 4K puede tomar un momento...</p>
                    )}
                  </div>
                )}

                {/* Single Image Result */}
                {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && (
                  <img 
                    src={resultImage} 
                    alt="Result" 
                    className="max-w-full max-h-[70vh] rounded-lg shadow-2xl object-contain border border-slate-800"
                  />
                )}

                {/* Batch Image Results */}
                {mode === AppMode.BATCH_EDIT_SHADOW && resultBatchItems.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-h-[70vh] overflow-y-auto p-2">
                    {resultBatchItems.map(item => (
                      <div key={item.id} className="bg-slate-900 rounded-lg p-3 border border-slate-800 flex flex-col items-center space-y-2 shadow-lg">
                        {item.loading && (
                           <div className="w-full h-48 bg-slate-800 flex items-center justify-center rounded-md">
                             <div className="w-10 h-10 border-2 border-blue-600/30 border-t-blue-500 rounded-full animate-spin"></div>
                           </div>
                        )}
                        {item.errorMessage && !item.loading && (
                          <div className="w-full h-48 bg-red-900/30 text-red-400 flex items-center justify-center rounded-md text-sm">
                            {item.errorMessage}
                          </div>
                        )}
                        {item.resultImage && !item.loading && (
                          <img 
                            src={item.resultImage} 
                            alt={`Result for ${item.file.name}`} 
                            className="max-w-full h-48 object-contain rounded-md border border-slate-700"
                          />
                        )}
                        <p className="text-xs text-slate-400 truncate w-full text-center">
                           Original: {item.file.name} ({item.originalDims?.w}x{item.originalDims?.h}px)
                        </p>
                        {item.resultImage && (
                           <div className="flex gap-2 mt-2">
                             <Button 
                               variant="secondary" 
                               onClick={() => downloadResizedImage(item.resultImage!, `autoshadow-${item.id}.png`, 'image/png', item.originalDims?.w, item.originalDims?.h)}
                               className="text-xs py-1.5 px-3"
                             >
                               Descargar PNG
                             </Button>
                             <Button 
                               variant="secondary" 
                               onClick={() => downloadResizedImage(item.resultImage!, `autoshadow-${item.id}.jpg`, 'image/jpeg', item.originalDims?.w, item.originalDims?.h)}
                               className="text-xs py-1.5 px-3 bg-slate-800"
                             >
                               Descargar JPG
                             </Button>
                           </div>
                        )}
                      </div>
                    ))}
                  </div>
                )}

                {/* Text Analysis Result */}
                {resultText && (
                  <div className="w-full max-w-2xl bg-slate-900 p-6 rounded-xl border border-slate-800 overflow-y-auto max-h-[70vh]">
                    <h3 className="text-xl font-bold text-emerald-400 mb-4 flex items-center gap-2">
                      <span className="bg-emerald-500/10 p-1 rounded">✨</span> Análisis de Vehículo
                    </h3>
                    <div className="prose prose-invert prose-slate max-w-none whitespace-pre-wrap leading-relaxed">
                      {resultText}
                    </div>
                    <div className="mt-8 pt-4 border-t border-slate-800 text-xs text-slate-500 text-center">
                      Nota: Este análisis es generado por IA y puede contener imprecisiones sobre especificaciones técnicas exactas.
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export enum AppMode {
  EDIT_SHADOW = 'EDIT_SHADOW',
  GENERATE = 'GENERATE',
  ANALYZE = 'ANALYZE',
  BATCH_EDIT_SHADOW = 'BATCH_EDIT_SHADOW', // New mode for batch processing
}

export enum AspectRatio {
  SQUARE = "1:1",
  PORTRAIT_3_4 = "3:4",
  PORTRAIT_9_16 = "9:16",
  LANDSCAPE_4_3 = "4:3",
  LANDSCAPE_16_9 = "16:9",
  LANDSCAPE_21_9 = "21:9",
  STANDARD_2_3 = "2:3",
  STANDARD_3_2 = "3:2"
}

export enum ImageSize {
  SIZE_1K = "1K",
  SIZE_2K = "2K",
  SIZE_4K = "4K"
}

export interface GeneratedContent {
  imageUrl?: string;
  text?: string;
}

export interface LoadingState {
  isLoading: boolean;
  message: string;
}

// New interface for managing images in batch mode
export interface BatchImageItem {
  id: string; // Unique identifier for each image in the batch
  file: File;
  previewUrl: string;
  originalDims: { w: number; h: number } | null;
  resultImage?: string | null;
  loading?: boolean;
  errorMessage?: string;
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppMode, AspectRatio, ImageSize, LoadingState, BatchImageItem } from './types';
import { editCarImage, generateCarImage, analyzeCarImage } from './services/geminiService';
import { fileToBase64, downloadResizedImage, downloadAllBatchImages } from './utils';
import { Button } from './components/Button';

// Icons as simple SVGs
const UploadIcon = () => (
  <svg className="w-8 h-8 mb-3 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
);
const CarIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 19H5V8h14m-3-5v2.206l-1.6 2.4h-6.8L6 5.206V3h12zM7 15a2 2 0 100 4 2 2 0 000-4zm10 0a2 2 0 100 4 2 2 0 000-4z" /></svg>
);
const SparkIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 3.214L13 21l-2.286-6.857L5 12l5.714-3.214z" /></svg>
);
const CloseIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
);
const DownloadIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
);

// Prompts for Shadow Editing
const PROMPT_A_MIRROR = "The vehicle pictured in the source image now rests on a highly polished, glossy white studio floor. Below the vehicle is a realistic, soft contact shadow, darkest and sharpest immediately under the tires and lower chassis to anchor it to the ground, and diffusing gently outwards. Furthermore, there are sharp, realistic reflections of the vehicle's body and wheels visible on the glossy surface. All other elements from the original source image, including the entire background environment, original lighting, and any text or graphics present in the frame, remain unchanged.";

const PROMPT_B_DARK = "Based strictly on image, the vehicle pictured now casts a realistic, soft contact shadow on the surface directly beneath it. This shadow is darkest immediately under the tires and chassis to anchor the car to the ground, and fades gently outwards. All other elements of image, including the vehicle's specific appearance, the entire background environment, original lighting, reflections, and any text or graphics present in the frame, remain absolutely identical to the original source image.";


const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.EDIT_SHADOW);
  // Single image states (for EDIT_SHADOW, GENERATE, ANALYZE modes)
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [originalDims, setOriginalDims] = useState<{w: number, h: number} | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [resultText, setResultText] = useState<string | null>(null);

  // Batch image states (for BATCH_EDIT_SHADOW mode)
  const [selectedBatchItems, setSelectedBatchItems] = useState<BatchImageItem[]>([]);
  const [resultBatchItems, setResultBatchItems] = useState<BatchImageItem[]>([]);

  // Settings
  const [prompt, setPrompt] = useState<string>(""); // Used for GENERATE and ANALYZE
  const [genAspectRatio, setGenAspectRatio] = useState<AspectRatio>(AspectRatio.LANDSCAPE_16_9);
  const [genImageSize, setGenImageSize] = useState<ImageSize>(ImageSize.SIZE_2K);

  const [loading, setLoading] = useState<LoadingState>({ isLoading: false, message: '' });
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const batchFileInputRef = useRef<HTMLInputElement>(null);

  // Handle PWA Install Prompt
  useEffect(() => {
    const handler = (e: any) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handler);

    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (!installPrompt) return;

    // Show the install prompt
    installPrompt.prompt();

    // Wait for the user to respond to the prompt
    installPrompt.userChoice.then((choiceResult: any) => {
      if (choiceResult.outcome === 'accepted') {
        console.log('User accepted the install prompt');
        setInstallPrompt(null);
      } else {
        console.log('User dismissed the install prompt');
      }
    });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>, isBatch: boolean = false) => {
    if (!event.target.files) return;

    const files = Array.from(event.target.files) as File[];

    if (isBatch) {
      const newItems: BatchImageItem[] = [];
      const currentCount = selectedBatchItems.length;
      const maxBatchSize = 6;

      for (let i = 0; i < files.length && currentCount + i < maxBatchSize; i++) {
        const file = files[i];
        const id = `${file.name}-${Date.now()}-${i}`;
        const url = URL.createObjectURL(file);

        const img = new Image();
        img.onload = () => {
          setSelectedBatchItems(prev => prev.map(item => 
            item.id === id ? { ...item, originalDims: { w: img.width, h: img.height } } : item
          ));
        };
        img.src = url;

        newItems.push({ id, file, previewUrl: url, originalDims: null, loading: false });
      }
      setSelectedBatchItems(prev => [...prev, ...newItems]);
      setResultBatchItems([]); // Clear previous batch results
    } else {
      const file = files[0];
      setSelectedFile(file);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
      setResultImage(null);
      setResultText(null);

      const img = new Image();
      img.onload = () => {
        setOriginalDims({ w: img.width, h: img.height });
      };
      img.src = url;
    }
    // Clear the input value so the same file can be selected again
    if (event.target) {
      event.target.value = '';
    }
  };

  const handleRemoveImage = useCallback((e: React.MouseEvent, isBatch: boolean = false, itemId?: string) => {
    e.stopPropagation();
    if (isBatch && itemId) {
      setSelectedBatchItems(prev => prev.filter(item => item.id !== itemId));
      setResultBatchItems(prev => prev.filter(item => item.id !== itemId));
    } else {
      setSelectedFile(null);
      setPreviewUrl(null);
      setOriginalDims(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  }, []);

  const handleAction = async (specificPrompt?: string) => {
    setLoading({ isLoading: true, message: 'Procesando con Gemini AI...' });
    setResultImage(null);
    setResultText(null);
    setResultBatchItems([]); // Clear batch results before new processing

    const promptToUse = specificPrompt || prompt;

    try {
      if (mode === AppMode.EDIT_SHADOW) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const editedImage = await editCarImage(base64, promptToUse, selectedFile.type);
        setResultImage(editedImage);
      } else if (mode === AppMode.GENERATE) {
        const generated = await generateCarImage(promptToUse, genAspectRatio, genImageSize);
        setResultImage(generated);
      } else if (mode === AppMode.ANALYZE) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const analysis = await analyzeCarImage(base64, promptToUse || "Analiza este vehículo: marca, modelo estimado, color y características visibles.", selectedFile.type);
        setResultText(analysis);
      } else if (mode === AppMode.BATCH_EDIT_SHADOW) {
        if (selectedBatchItems.length === 0) throw new Error("Selecciona al menos una imagen para el procesamiento por lotes.");

        const processedResults: BatchImageItem[] = await Promise.all(selectedBatchItems.map(async (item) => {
          setSelectedBatchItems(prev => prev.map(i => i.id === item.id ? { ...i, loading: true, errorMessage: undefined } : i));
          try {
            const base64 = await fileToBase64(item.file);
            const editedImage = await editCarImage(base64, promptToUse, item.file.type);
            return { ...item, resultImage: editedImage, loading: false, errorMessage: undefined };
          } catch (error) {
            console.error(`Error processing batch item ${item.id}:`, error);
            return { ...item, resultImage: null, loading: false, errorMessage: "Error procesando imagen" };
          }
        }));
        setResultBatchItems(processedResults);
        // Clear loading states from selectedBatchItems as results are in resultBatchItems
        setSelectedBatchItems(prev => prev.map(item => ({ ...item, loading: false })));
      }
    } catch (error) {
      console.error(error);
      alert("Hubo un error procesando tu solicitud. Por favor intenta de nuevo.");
    } finally {
      setLoading({ isLoading: false, message: '' });
    }
  };

  const resetState = useCallback((newMode: AppMode) => {
    setMode(newMode);
    setResultImage(null);
    setResultText(null);
    setSelectedFile(null);
    setPreviewUrl(null);
    setOriginalDims(null);
    setSelectedBatchItems([]);
    setResultBatchItems([]);
    if (fileInputRef.current) fileInputRef.current.value = '';
    if (batchFileInputRef.current) batchFileInputRef.current.value = '';

    // Set default prompts based on mode
    if (newMode === AppMode.GENERATE) {
      setPrompt("Un auto deportivo futurista color plata conduciendo bajo la lluvia en una ciudad cyberpunk neon.");
    } else if (newMode === AppMode.ANALYZE) {
      setPrompt("Analiza este vehículo: marca, modelo estimado, y estilo.");
    } else {
      setPrompt(""); // Clear prompt for modes that use buttons or no prompt
    }
  }, []); // Empty dependency array means this function is created once

  const hasSuccessfulBatchResults = resultBatchItems.some(item => item.resultImage);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-blue-500/30">
      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg">
              <CarIcon />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-400">
              AutoShadow AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
            {installPrompt && (
              <button
                onClick={handleInstallClick}
                className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-medium rounded-full border border-slate-700 transition-colors"
              >
                <DownloadIcon />
                Instalar App
              </button>
            )}
            <div className="text-xs text-slate-500 font-mono hidden sm:block">
              Powered by Gemini 2.5 & 3.0
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Navigation Tabs */}
        <div className="flex flex-wrap gap-2 mb-8 p-1 bg-slate-900/80 rounded-xl border border-slate-800 w-full md:w-fit">
          <button
            onClick={() => resetState(AppMode.EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.EDIT_SHADOW ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Editar & Sombras
          </button>
          <button
            onClick={() => resetState(AppMode.BATCH_EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.BATCH_EDIT_SHADOW ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Lotes
          </button>
          <button
            onClick={() => resetState(AppMode.GENERATE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.GENERATE ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Generar Nuevo
          </button>
          <button
            onClick={() => resetState(AppMode.ANALYZE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.ANALYZE ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Analizar
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Controls Column */}
          <div className="lg:col-span-4 space-y-6">

            {/* Image Upload Area (for single image modes) */}
            {(mode === AppMode.EDIT_SHADOW || mode === AppMode.ANALYZE) && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imagen Original</h2>
                <div 
                  className={`border-2 border-dashed rounded-xl h-48 flex flex-col items-center justify-center cursor-pointer transition-colors ${previewUrl ? 'border-slate-600 bg-slate-800/50' : 'border-slate-700 hover:border-blue-500 hover:bg-slate-800/50'}`}
                  onClick={() => fileInputRef.current?.click()}
                  style={previewUrl ? { backgroundImage: `url(${previewUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' } : {}}
                >
                  {!previewUrl && (
                    <>
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Click para subir auto</p>
                      <p className="text-xs text-slate-500 mt-1">JPG, PNG</p>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*" 
                    onChange={(e) => handleFileChange(e, false)} 
                  />
                </div>
                {previewUrl && (
                  <button 
                    onClick={(e) => handleRemoveImage(e, false)}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover imagen
                  </button>
                )}
                {originalDims && (
                  <p className="text-xs text-slate-600 mt-2 text-center">
                    Dimensiones: {originalDims.w} x {originalDims.h} px
                  </p>
                )}
              </div>
            )}

            {/* Batch Image Upload Area */}
            {mode === AppMode.BATCH_EDIT_SHADOW && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imágenes Originales (Lotes)</h2>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {selectedBatchItems.map(item => (
                    <div key={item.id} className="relative w-full h-32 rounded-xl border border-slate-700 bg-slate-800/50 overflow-hidden group">
                      <img src={item.previewUrl} alt="Preview" className="w-full h-full object-cover" />
                      <button 
                        onClick={(e) => handleRemoveImage(e, true, item.id)}
                        className="absolute top-1 right-1 bg-red-600 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                        aria-label="Remover imagen"
                      >
                        <CloseIcon />
                      </button>
                      {item.originalDims && (
                        <p className="absolute bottom-1 left-1 text-white text-[10px] bg-black/50 px-1 rounded">
                          {item.originalDims.w}x{item.originalDims.h}
                        </p>
                      )}
                    </div>
                  ))}
                  {selectedBatchItems.length < 6 && (
                    <div 
                      className="border-2 border-dashed rounded-xl h-32 flex flex-col items-center justify-center cursor-pointer transition-colors border-slate-700 hover:border-blue-500 hover:bg-slate-800/50"
                      onClick={() => batchFileInputRef.current?.click()}
                    >
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Agregar ({6 - selectedBatchItems.length})</p>
                      <input 
                        type="file" 
                        ref={batchFileInputRef} 
                        className="hidden" 
                        accept="image/*" 
                        multiple
                        onChange={(e) => handleFileChange(e, true)} 
                      />
                    </div>
                  )}
                </div>
                 {selectedBatchItems.length > 0 && (
                  <button 
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedBatchItems([]);
                      setResultBatchItems([]);
                      if (batchFileInputRef.current) batchFileInputRef.current.value = '';
                    }}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover todas las imágenes
                  </button>
                )}
              </div>
            )}


            {/* Prompt & Settings Area */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl space-y-4">
              <h2 className="text-lg font-semibold text-white">Configuración</h2>

              {/* Prompt Input - Shown for TEXT_EDIT, Generate and Analyze modes */}
              {(mode === AppMode.GENERATE || mode === AppMode.ANALYZE) && (
                <div className="space-y-2">
                  <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">
                    Prompt (Instrucción)
                  </label>
                  <textarea
                    className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-sm text-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none resize-none h-32"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe lo que quieres hacer..."
                  />
                </div>
              )}

              {mode === AppMode.GENERATE && (
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Relación Aspecto</label>
                    <select 
                      value={genAspectRatio}
                      onChange={(e) => setGenAspectRatio(e.target.value as AspectRatio)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(AspectRatio).map(ratio => (
                        <option key={ratio} value={ratio}>{ratio}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Resolución</label>
                    <select 
                      value={genImageSize}
                      onChange={(e) => setGenImageSize(e.target.value as ImageSize)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(ImageSize).map(size => (
                        <option key={size} value={size}>{size}</option>
                      ))}
                    </select>
                  </div>
                </div>
              )}

              {/* Action Buttons */}
              {(mode === AppMode.EDIT_SHADOW || mode === AppMode.BATCH_EDIT_SHADOW) ? (
                <div className="space-y-3 mt-4">
                  <Button 
                    onClick={() => handleAction(PROMPT_A_MIRROR)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/50"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Espejo
                  </Button>
                  <Button 
                    onClick={() => handleAction(PROMPT_B_DARK)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-slate-700 hover:bg-slate-600 text-slate-100 border border-slate-600"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Oscura
                  </Button>
                </div>
              ) : (
                <Button 
                  onClick={() => handleAction()} 
                  isLoading={loading.isLoading}
                  className="w-full mt-4"
                  disabled={!selectedFile && mode !== AppMode.GENERATE} // Disable if no file for Edit/Analyze/TextEdit, but not for Generate
                >
                  {!loading.isLoading && <SparkIcon />}
                  {loading.isLoading ? loading.message : 
                   mode === AppMode.ANALYZE ? 'Analizar' : 
                   'Generar'}
                </Button>
              )}
            </div>
          </div>

          {/* Result Column */}
          <div className="lg:col-span-8">
            <div className="bg-slate-900 rounded-2xl border border-slate-800 shadow-xl h-full min-h-[500px] flex flex-col overflow-hidden relative">
              <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50">
                <h2 className="text-lg font-semibold text-white">Resultado</h2>
                {(resultImage || resultBatchItems.length > 0) && (
                  <div className="flex gap-2">
                    {/* For single image mode */}
                    {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && ( // Ensure it's not batch mode
                      <>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.png`, 'image/png', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3"
                        >
                          Descargar PNG
                        </Button>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.jpg`, 'image/jpeg', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3 bg-slate-800"
                        >
                          Descargar JPG
                        </Button>
                      </>
                    )}
                    {/* Batch mode global download */}
                    {mode === AppMode.BATCH_EDIT_SHADOW && hasSuccessfulBatchResults && (
                      <Button
                        variant="primary"
                        onClick={() => downloadAllBatchImages(resultBatchItems)}
                        isLoading={loading.isLoading}
                        className="text-xs py-1.5 px-3"
                      >
                        Descargar Todo (Zip)
                      </Button>
                    )}
                  </div>
                )}
              </div>

              <div className="flex-1 bg-slate-950 flex items-center justify-center p-4 relative">

                {/* Empty State */}
                {!resultImage && !resultText && !loading.isLoading && resultBatchItems.length === 0 && (
                  <div className="text-center text-slate-600 max-w-sm">
                    <div className="mx-auto w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4 border border-slate-800">
                      <SparkIcon />
                    </div>
                    <p className="text-lg font-medium text-slate-500">Listo para crear magia</p>
                    {mode === AppMode.BATCH_EDIT_SHADOW ? (
                      <p className="text-sm mt-2">Sube hasta 6 imágenes para procesar por lotes.</p>
                    ) : (
                      <p className="text-sm mt-2">Sube una imagen o selecciona un tipo de sombra.</p>
                    )}
                  </div>
                )}

                {/* Loading State */}
                {loading.isLoading && (
                  <div className="absolute inset-0 z-10 bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center">
                    <div className="w-16 h-16 border-4 border-blue-600/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                    <p className="text-blue-400 animate-pulse">{loading.message}</p>
                    {mode === AppMode.GENERATE && genImageSize === ImageSize.SIZE_4K && (
                      <p className="text-xs text-slate-500 mt-2">Generar en 4K puede tomar un momento...</p>
                    )}
                  </div>
                )}

                {/* Single Image Result */}
                {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && (
                  <img 
                    src={resultImage} 
                    alt="Result" 
                    className="max-w-full max-h-[70vh] rounded-lg shadow-2xl object-contain border border-slate-800"
                  />
                )}

                {/* Batch Image Results */}
                {mode === AppMode.BATCH_EDIT_SHADOW && resultBatchItems.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-h-[70vh] overflow-y-auto p-2">
                    {resultBatchItems.map(item => (
                      <div key={item.id} className="bg-slate-900 rounded-lg p-3 border border-slate-800 flex flex-col items-center space-y-2 shadow-lg">
                        {item.loading && (
                           <div className="w-full h-48 bg-slate-800 flex items-center justify-center rounded-md">
                             <div className="w-10 h-10 border-2 border-blue-600/30 border-t-blue-500 rounded-full animate-spin"></div>
                           </div>
                        )}
                        {item.errorMessage && !item.loading && (
                          <div className="w-full h-48 bg-red-900/30 text-red-400 flex items-center justify-center rounded-md text-sm">
                            {item.errorMessage}
                          </div>
                        )}
                        {item.resultImage && !item.loading && (
                          <img 
                            src={item.resultImage} 
                            alt={`Result for ${item.file.name}`} 
                            className="max-w-full h-48 object-contain rounded-md border border-slate-700"
                          />
                        )}
                        <p className="text-xs text-slate-400 truncate w-full text-center">
                           Original: {item.file.name} ({item.originalDims?.w}x{item.originalDims?.h}px)
                        </p>
                        {item.resultImage && (
                           <div className="flex gap-2 mt-2">
                             <Button 
                               variant="secondary" 
                               onClick={() => downloadResizedImage(item.resultImage!, `autoshadow-${item.id}.png`, 'image/png', item.originalDims?.w, item.originalDims?.h)}
                               className="text-xs py-1.5 px-3"
                             >
                               Descargar PNG
                             </Button>
                             <Button 
                               variant="secondary" 
                               onClick={() => downloadResizedImage(item.resultImage!, `autoshadow-${item.id}.jpg`, 'image/jpeg', item.originalDims?.w, item.originalDims?.h)}
                               className="text-xs py-1.5 px-3 bg-slate-800"
                             >
                               Descargar JPG
                             </Button>
                           </div>
                        )}
                      </div>
                    ))}
                  </div>
                )}

                {/* Text Analysis Result */}
                {resultText && (
                  <div className="w-full max-w-2xl bg-slate-900 p-6 rounded-xl border border-slate-800 overflow-y-auto max-h-[70vh]">
                    <h3 className="text-xl font-bold text-emerald-400 mb-4 flex items-center gap-2">
                      <span className="bg-emerald-500/10 p-1 rounded">✨</span> Análisis de Vehículo
                    </h3>
                    <div className="prose prose-invert prose-slate max-w-none whitespace-pre-wrap leading-relaxed">
                      {resultText}
                    </div>
                    <div className="mt-8 pt-4 border-t border-slate-800 text-xs text-slate-500 text-center">
                      Nota: Este análisis es generado por IA y puede contener imprecisiones sobre especificaciones técnicas exactas.
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export enum AppMode {
  EDIT_SHADOW = 'EDIT_SHADOW',
  BACKGROUND_EDIT = 'BACKGROUND_EDIT', // New mode for background editing
  GENERATE = 'GENERATE',
  ANALYZE = 'ANALYZE',
  BATCH_EDIT_SHADOW = 'BATCH_EDIT_SHADOW', // New mode for batch processing
}

export enum AspectRatio {
  SQUARE = "1:1",
  PORTRAIT_3_4 = "3:4",
  PORTRAIT_9_16 = "9:16",
  LANDSCAPE_4_3 = "4:3",
  LANDSCAPE_16_9 = "16:9",
  LANDSCAPE_21_9 = "21:9",
  STANDARD_2_3 = "2:3",
  STANDARD_3_2 = "3:2"
}

export enum ImageSize {
  SIZE_1K = "1K",
  SIZE_2K = "2K",
  SIZE_4K = "4K"
}

export interface GeneratedContent {
  imageUrl?: string;
  text?: string;
}

export interface LoadingState {
  isLoading: boolean;
  message: string;
}

// New interface for managing images in batch mode
export interface BatchImageItem {
  id: string; // Unique identifier for each image in the batch
  file: File;
  previewUrl: string;
  originalDims: { w: number; h: number } | null;
  resultImage?: string | null;
  loading?: boolean;
  errorMessage?: string;
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { AppMode, AspectRatio, ImageSize, LoadingState, BatchImageItem } from './types';
import { editCarImage, generateCarImage, analyzeCarImage } from './services/geminiService';
import { fileToBase64, downloadResizedImage, downloadAllBatchImages } from './utils';
import { Button } from './components/Button';

// Icons as simple SVGs
const UploadIcon = () => (
  <svg className="w-8 h-8 mb-3 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
);
const CarIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 19H5V8h14m-3-5v2.206l-1.6 2.4h-6.8L6 5.206V3h12zM7 15a2 2 0 100 4 2 2 0 000-4zm10 0a2 2 0 100 4 2 2 0 000-4z" /></svg>
);
const SparkIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 3.214L13 21l-2.286-6.857L5 12l5.714-3.214z" /></svg>
);
const CloseIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
);
const DownloadIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
);

// Prompts for Shadow Editing
const PROMPT_A_MIRROR = "The vehicle pictured in the source image now rests on a highly polished, glossy white studio floor. Below the vehicle is a realistic, soft contact shadow, darkest and sharpest immediately under the tires and lower chassis to anchor it to the ground, and diffusing gently outwards. Furthermore, there are sharp, realistic reflections of the vehicle's body and wheels visible on the glossy surface. All other elements from the original source image, including the entire background environment, original lighting, and any text or graphics present in the frame, remain unchanged.";

const PROMPT_B_DARK = "Based strictly on image, the vehicle pictured now casts a realistic, soft contact shadow on the surface directly beneath it. This shadow is darkest immediately under the tires and chassis to anchor the car to the ground, and fades gently outwards. All other elements of image, including the vehicle's specific appearance, the entire background environment, original lighting, reflections, and any text or graphics present in the frame, remain absolutely identical to the original source image.";


const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.EDIT_SHADOW);
  // Single image states (for EDIT_SHADOW, BACKGROUND_EDIT, GENERATE, ANALYZE modes)
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [originalDims, setOriginalDims] = useState<{w: number, h: number} | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [resultText, setResultText] = useState<string | null>(null);

  // Batch image states (for BATCH_EDIT_SHADOW mode)
  const [selectedBatchItems, setSelectedBatchItems] = useState<BatchImageItem[]>([]);
  const [resultBatchItems, setResultBatchItems] = useState<BatchImageItem[]>([]);

  // Settings
  const [prompt, setPrompt] = useState<string>(""); // Used for BACKGROUND_EDIT, GENERATE and ANALYZE
  const [genAspectRatio, setGenAspectRatio] = useState<AspectRatio>(AspectRatio.LANDSCAPE_16_9);
  const [genImageSize, setGenImageSize] = useState<ImageSize>(ImageSize.SIZE_2K);

  const [loading, setLoading] = useState<LoadingState>({ isLoading: false, message: '' });
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const batchFileInputRef = useRef<HTMLInputElement>(null);

  // Handle PWA Install Prompt
  useEffect(() => {
    const handler = (e: any) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handler);

    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (!installPrompt) return;

    // Show the install prompt
    installPrompt.prompt();

    // Wait for the user to respond to the prompt
    installPrompt.userChoice.then((choiceResult: any) => {
      if (choiceResult.outcome === 'accepted') {
        console.log('User accepted the install prompt');
        setInstallPrompt(null);
      } else {
        console.log('User dismissed the install prompt');
      }
    });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>, isBatch: boolean = false) => {
    if (!event.target.files) return;

    const files = Array.from(event.target.files) as File[];

    if (isBatch) {
      const newItems: BatchImageItem[] = [];
      const currentCount = selectedBatchItems.length;
      const maxBatchSize = 6;

      for (let i = 0; i < files.length && currentCount + i < maxBatchSize; i++) {
        const file = files[i];
        const id = `${file.name}-${Date.now()}-${i}`;
        const url = URL.createObjectURL(file);

        const img = new Image();
        img.onload = () => {
          setSelectedBatchItems(prev => prev.map(item => 
            item.id === id ? { ...item, originalDims: { w: img.width, h: img.height } } : item
          ));
        };
        img.src = url;

        newItems.push({ id, file, previewUrl: url, originalDims: null, loading: false });
      }
      setSelectedBatchItems(prev => [...prev, ...newItems]);
      setResultBatchItems([]); // Clear previous batch results
    } else {
      const file = files[0];
      setSelectedFile(file);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
      setResultImage(null);
      setResultText(null);

      const img = new Image();
      img.onload = () => {
        setOriginalDims({ w: img.width, h: img.height });
      };
      img.src = url;
    }
    // Clear the input value so the same file can be selected again
    if (event.target) {
      event.target.value = '';
    }
  };

  const handleRemoveImage = useCallback((e: React.MouseEvent, isBatch: boolean = false, itemId?: string) => {
    e.stopPropagation();
    if (isBatch && itemId) {
      setSelectedBatchItems(prev => prev.filter(item => item.id !== itemId));
      setResultBatchItems(prev => prev.filter(item => item.id !== itemId));
    } else {
      setSelectedFile(null);
      setPreviewUrl(null);
      setOriginalDims(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  }, []);

  const handleAction = async (specificPrompt?: string) => {
    setLoading({ isLoading: true, message: 'Procesando con Gemini AI...' });
    setResultImage(null);
    setResultText(null);
    setResultBatchItems([]); // Clear batch results before new processing

    const promptToUse = specificPrompt || prompt;

    try {
      if (mode === AppMode.EDIT_SHADOW || mode === AppMode.BACKGROUND_EDIT) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const editedImage = await editCarImage(base64, promptToUse, selectedFile.type);
        setResultImage(editedImage);
      } else if (mode === AppMode.GENERATE) {
        const generated = await generateCarImage(promptToUse, genAspectRatio, genImageSize);
        setResultImage(generated);
      } else if (mode === AppMode.ANALYZE) {
        if (!selectedFile) throw new Error("Selecciona una imagen primero.");
        const base64 = await fileToBase64(selectedFile);
        const analysis = await analyzeCarImage(base64, promptToUse || "Analiza este vehículo: marca, modelo estimado, color y características visibles.", selectedFile.type);
        setResultText(analysis);
      } else if (mode === AppMode.BATCH_EDIT_SHADOW) {
        if (selectedBatchItems.length === 0) throw new Error("Selecciona al menos una imagen para el procesamiento por lotes.");

        const processedResults: BatchImageItem[] = await Promise.all(selectedBatchItems.map(async (item) => {
          setSelectedBatchItems(prev => prev.map(i => i.id === item.id ? { ...i, loading: true, errorMessage: undefined } : i));
          try {
            const base64 = await fileToBase64(item.file);
            const editedImage = await editCarImage(base64, promptToUse, item.file.type);
            return { ...item, resultImage: editedImage, loading: false, errorMessage: undefined };
          } catch (error) {
            console.error(`Error processing batch item ${item.id}:`, error);
            return { ...item, resultImage: null, loading: false, errorMessage: "Error procesando imagen" };
          }
        }));
        setResultBatchItems(processedResults);
        // Clear loading states from selectedBatchItems as results are in resultBatchItems
        setSelectedBatchItems(prev => prev.map(item => ({ ...item, loading: false })));
      }
    } catch (error) {
      console.error(error);
      alert("Hubo un error procesando tu solicitud. Por favor intenta de nuevo.");
    } finally {
      setLoading({ isLoading: false, message: '' });
    }
  };

  const resetState = useCallback((newMode: AppMode) => {
    setMode(newMode);
    setResultImage(null);
    setResultText(null);
    setSelectedFile(null);
    setPreviewUrl(null);
    setOriginalDims(null);
    setSelectedBatchItems([]);
    setResultBatchItems([]);
    if (fileInputRef.current) fileInputRef.current.value = '';
    if (batchFileInputRef.current) batchFileInputRef.current.value = '';

    // Set default prompts based on mode
    if (newMode === AppMode.GENERATE) {
      setPrompt("Un auto deportivo futurista color plata conduciendo bajo la lluvia en una ciudad cyberpunk neon.");
    } else if (newMode === AppMode.ANALYZE) {
      setPrompt("Analiza este vehículo: marca, modelo estimado, y estilo.");
    } else if (newMode === AppMode.BACKGROUND_EDIT) {
      setPrompt("Cambia el fondo de este auto por un paisaje urbano nocturno con luces de neón.");
    }
    else {
      setPrompt(""); // Clear prompt for modes that use buttons or no prompt
    }
  }, []); // Empty dependency array means this function is created once

  const hasSuccessfulBatchResults = resultBatchItems.some(item => item.resultImage);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-blue-500/30">
      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg">
              <CarIcon />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-400">
              AutoShadow AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
            {installPrompt && (
              <button
                onClick={handleInstallClick}
                className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-medium rounded-full border border-slate-700 transition-colors"
              >
                <DownloadIcon />
                Instalar App
              </button>
            )}
            <div className="text-xs text-slate-500 font-mono hidden sm:block">
              Powered by Gemini 2.5 & 3.0
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Navigation Tabs */}
        <div className="flex flex-wrap gap-2 mb-8 p-1 bg-slate-900/80 rounded-xl border border-slate-800 w-full md:w-fit">
          <button
            onClick={() => resetState(AppMode.EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.EDIT_SHADOW ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Editar & Sombras
          </button>
          <button
            onClick={() => resetState(AppMode.BACKGROUND_EDIT)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.BACKGROUND_EDIT ? 'bg-green-600 text-white shadow-lg shadow-green-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Edición de Fondos
          </button>
          <button
            onClick={() => resetState(AppMode.BATCH_EDIT_SHADOW)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.BATCH_EDIT_SHADOW ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Lotes
          </button>
          <button
            onClick={() => resetState(AppMode.GENERATE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.GENERATE ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Generar Nuevo
          </button>
          <button
            onClick={() => resetState(AppMode.ANALYZE)}
            className={`flex-1 md:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-all ${mode === AppMode.ANALYZE ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            Analizar
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Controls Column */}
          <div className="lg:col-span-4 space-y-6">

            {/* Image Upload Area (for single image modes) */}
            {(mode === AppMode.EDIT_SHADOW || mode === AppMode.ANALYZE || mode === AppMode.BACKGROUND_EDIT) && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imagen Original</h2>
                <div 
                  className={`border-2 border-dashed rounded-xl h-48 flex flex-col items-center justify-center cursor-pointer transition-colors ${previewUrl ? 'border-slate-600 bg-slate-800/50' : 'border-slate-700 hover:border-blue-500 hover:bg-slate-800/50'}`}
                  onClick={() => fileInputRef.current?.click()}
                  style={previewUrl ? { backgroundImage: `url(${previewUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' } : {}}
                >
                  {!previewUrl && (
                    <>
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Click para subir auto</p>
                      <p className="text-xs text-slate-500 mt-1">JPG, PNG</p>
                    </>
                  )}
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*" 
                    onChange={(e) => handleFileChange(e, false)} 
                  />
                </div>
                {previewUrl && (
                  <button 
                    onClick={(e) => handleRemoveImage(e, false)}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover imagen
                  </button>
                )}
                {originalDims && (
                  <p className="text-xs text-slate-600 mt-2 text-center">
                    Dimensiones: {originalDims.w} x {originalDims.h} px
                  </p>
                )}
              </div>
            )}

            {/* Batch Image Upload Area */}
            {mode === AppMode.BATCH_EDIT_SHADOW && (
              <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
                <h2 className="text-lg font-semibold text-white mb-4">Imágenes Originales (Lotes)</h2>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {selectedBatchItems.map(item => (
                    <div key={item.id} className="relative w-full h-32 rounded-xl border border-slate-700 bg-slate-800/50 overflow-hidden group">
                      <img src={item.previewUrl} alt="Preview" className="w-full h-full object-cover" />
                      <button 
                        onClick={(e) => handleRemoveImage(e, true, item.id)}
                        className="absolute top-1 right-1 bg-red-600 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                        aria-label="Remover imagen"
                      >
                        <CloseIcon />
                      </button>
                      {item.originalDims && (
                        <p className="absolute bottom-1 left-1 text-white text-[10px] bg-black/50 px-1 rounded">
                          {item.originalDims.w}x{item.originalDims.h}
                        </p>
                      )}
                    </div>
                  ))}
                  {selectedBatchItems.length < 6 && (
                    <div 
                      className="border-2 border-dashed rounded-xl h-32 flex flex-col items-center justify-center cursor-pointer transition-colors border-slate-700 hover:border-blue-500 hover:bg-slate-800/50"
                      onClick={() => batchFileInputRef.current?.click()}
                    >
                      <UploadIcon />
                      <p className="text-sm text-slate-400 font-medium">Agregar ({6 - selectedBatchItems.length})</p>
                      <input 
                        type="file" 
                        ref={batchFileInputRef} 
                        className="hidden" 
                        accept="image/*" 
                        multiple
                        onChange={(e) => handleFileChange(e, true)} 
                      />
                    </div>
                  )}
                </div>
                 {selectedBatchItems.length > 0 && (
                  <button 
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedBatchItems([]);
                      setResultBatchItems([]);
                      if (batchFileInputRef.current) batchFileInputRef.current.value = '';
                    }}
                    className="text-xs text-red-400 mt-2 hover:text-red-300 underline"
                  >
                    Remover todas las imágenes
                  </button>
                )}
              </div>
            )}


            {/* Prompt & Settings Area */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl space-y-4">
              <h2 className="text-lg font-semibold text-white">Configuración</h2>

              {/* Prompt Input - Shown for BACKGROUND_EDIT, Generate and Analyze modes */}
              {(mode === AppMode.GENERATE || mode === AppMode.ANALYZE || mode === AppMode.BACKGROUND_EDIT) && (
                <div className="space-y-2">
                  <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">
                    Prompt (Instrucción)
                  </label>
                  <textarea
                    className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-sm text-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none resize-none h-32"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe lo que quieres hacer..."
                  />
                </div>
              )}

              {mode === AppMode.GENERATE && (
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Relación Aspecto</label>
                    <select 
                      value={genAspectRatio}
                      onChange={(e) => setGenAspectRatio(e.target.value as AspectRatio)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(AspectRatio).map(ratio => (
                        <option key={ratio} value={ratio}>{ratio}</option>
                      ))}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Resolución</label>
                    <select 
                      value={genImageSize}
                      onChange={(e) => setGenImageSize(e.target.value as ImageSize)}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 outline-none focus:ring-blue-500 focus:border-blue-500"
                    >
                      {Object.values(ImageSize).map(size => (
                        <option key={size} value={size}>{size}</option>
                      ))}
                    </select>
                  </div>
                </div>
              )}

              {/* Action Buttons */}
              {(mode === AppMode.EDIT_SHADOW || mode === AppMode.BATCH_EDIT_SHADOW) ? (
                <div className="space-y-3 mt-4">
                  <Button 
                    onClick={() => handleAction(PROMPT_A_MIRROR)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/50"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Espejo
                  </Button>
                  <Button 
                    onClick={() => handleAction(PROMPT_B_DARK)} 
                    isLoading={loading.isLoading}
                    className="w-full bg-slate-700 hover:bg-slate-600 text-slate-100 border border-slate-600"
                    disabled={mode === AppMode.BATCH_EDIT_SHADOW ? selectedBatchItems.length === 0 : !selectedFile}
                  >
                    {!loading.isLoading && <SparkIcon />}
                    Sombra Oscura
                  </Button>
                </div>
              ) : (
                <Button 
                  onClick={() => handleAction()} 
                  isLoading={loading.isLoading}
                  className="w-full mt-4"
                  disabled={!selectedFile && mode !== AppMode.GENERATE || (mode === AppMode.BACKGROUND_EDIT && !selectedFile)} // Disable if no file for Edit/Analyze/TextEdit, but not for Generate
                >
                  {!loading.isLoading && <SparkIcon />}
                  {loading.isLoading ? loading.message : 
                   mode === AppMode.ANALYZE ? 'Analizar' : 
                   mode === AppMode.BACKGROUND_EDIT ? 'Aplicar Edición' :
                   'Generar'}
                </Button>
              )}
            </div>
          </div>

          {/* Result Column */}
          <div className="lg:col-span-8">
            <div className="bg-slate-900 rounded-2xl border border-slate-800 shadow-xl h-full min-h-[500px] flex flex-col overflow-hidden relative">
              <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50">
                <h2 className="text-lg font-semibold text-white">Resultado</h2>
                {(resultImage || resultBatchItems.length > 0) && (
                  <div className="flex gap-2">
                    {/* For single image mode */}
                    {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && ( // Ensure it's not batch mode
                      <>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.png`, 'image/png', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3"
                        >
                          Descargar PNG
                        </Button>
                        <Button 
                          variant="secondary" 
                          onClick={() => downloadResizedImage(resultImage, `autoshadow-${Date.now()}.jpg`, 'image/jpeg', originalDims?.w, originalDims?.h)}
                          className="text-xs py-1.5 px-3 bg-slate-800"
                        >
                          Descargar JPG
                        </Button>
                      </>
                    )}
                    {/* Batch mode global download */}
                    {mode === AppMode.BATCH_EDIT_SHADOW && hasSuccessfulBatchResults && (
                      <Button
                        variant="primary"
                        onClick={() => downloadAllBatchImages(resultBatchItems)}
                        isLoading={loading.isLoading}
                        className="text-xs py-1.5 px-3"
                      >
                        Descargar Todo (Zip)
                      </Button>
                    )}
                  </div>
                )}
              </div>

              <div className="flex-1 bg-slate-950 flex items-center justify-center p-4 relative">

                {/* Empty State */}
                {!resultImage && !resultText && !loading.isLoading && resultBatchItems.length === 0 && (
                  <div className="text-center text-slate-600 max-w-sm">
                    <div className="mx-auto w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4 border border-slate-800">
                      <SparkIcon />
                    </div>
                    <p className="text-lg font-medium text-slate-500">Listo para crear magia</p>
                    {mode === AppMode.BATCH_EDIT_SHADOW ? (
                      <p className="text-sm mt-2">Sube hasta 6 imágenes para procesar por lotes.</p>
                    ) : (
                      <p className="text-sm mt-2">Sube una imagen o selecciona un tipo de sombra.</p>
                    )}
                  </div>
                )}

                {/* Loading State */}
                {loading.isLoading && (
                  <div className="absolute inset-0 z-10 bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center">
                    <div className="w-16 h-16 border-4 border-blue-600/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                    <p className="text-blue-400 animate-pulse">{loading.message}</p>
                    {mode === AppMode.GENERATE && genImageSize === ImageSize.SIZE_4K && (
                      <p className="text-xs text-slate-500 mt-2">Generar en 4K puede tomar un momento...</p>
                    )}
                  </div>
                )}

                {/* Single Image Result */}
                {resultImage && mode !== AppMode.BATCH_EDIT_SHADOW && (
                  <img 
                    src={resultImage} 
                    alt="Result" 
                    className="max-w-full max-h-[70vh] rounded-lg shadow-2xl object-contain border border-slate-800"
                  />
                )}

                {/* Batch Image Results */}
                {mode === AppMode.BATCH_EDIT_SHADOW && resultBatchItems.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-h-[70vh] overflow-y-auto p-2">
                    {resultBatchItems.map(item => (
                      <div key={item.id} className="bg-slate-900 rounded-lg p-3 border border-slate-800 flex flex-col items-center space-y-2 shadow-lg">
                        {item.loading && (
                           <div className="w-full h-48 bg-slate-800 flex items-center justify-center rounded-md">
                             <div className="w-10 h-10 border-2 border-blue-600/30 border-t-blue-500 rounded-full animate-spin"></div>
                           </div>
                        )}
                        {item.errorMessage && !item.loading && (
                          <div className="w-full h-48 bg-red-900/30 text-red-400 flex items-center justify-center rounded-md text-sm">
                            {item.errorMessage}
                          </div>
                        )}
                        {item.resultImage && !item.loading && (
                          <img 
                            src={item.resultImage} 
                            alt={`Result for ${item.file.name}`} 
                            className="max-w-full h-48 object-contain rounded-md border border-slate-700"
                          />
                        )}
                        <p className="text-xs text-slate-400 truncate w-full text-center">
                           Original: {item.file.name} ({item.originalDims?.w}x{item.originalDims?.h}px)
                        </p>
                        {item.resultImage && (
                           <div className="flex gap-2 mt-2">
                             <Button 
                               variant="secondary" 
                               onClick={() => downloadResizedImage(item.resultImage!, `autoshadow-${item.id}.png`, 'image/png', item.originalDims?.w, item.originalDims?.h)}
                               className="text-xs py-1.5 px-3"
                             >
                               Descargar PNG
                             </Button>
                             <Button 
                               variant="secondary" 
