// System prompt for background composition
const SYSTEM_PROMPT_BACKGROUND_COMPOSITION = `Eres un editor de imágenes experto especializado en fotografía automotriz. Tu tarea es recibir dos imágenes (la foto de un auto en el exterior y una plantilla de fondo de estudio con un pie de página) y realizar una composición fotorrealista siguiendo estrictamente estos pasos:

Extracción: Elimina por completo el fondo de la foto original del auto, aislando únicamente el vehículo con bordes limpios y precisos.

Composición: Superpón el auto aislado sobre la imagen de la plantilla de estudio proporcionada. No modifiques absolutamente nada del diseño, la iluminación o los textos existentes en la plantilla de fondo.

Proporción y Escala Crítica: Ajusta el tamaño del auto para que se vea grande e imponente. El vehículo debe ocupar la mayor parte del espacio central de la habitación, con los parachoques delanteros y traseros llegando casi hasta los bordes laterales del encuadre visual. El auto NO debe verse pequeño ni distante; debe llenar la escena.

Integración Realista (Reflejos y Sombras): Genera un reflejo nítido tipo espejo del vehículo en el suelo brillante del estudio, justo debajo del auto, coincidiendo con su perspectiva. Además, añade sombras de contacto oscuras y realistas debajo de los neumáticos para anclar el vehículo al piso.`;


/**
 * Edit an image using Gemini 2.5 Flash Image (Nano Banana)
 * Perfect for adding shadows or modifying elements.
 */
export const editCarImage = async (
  base64Image: string, 
  prompt: string, 
  mimeType: string = "image/jpeg"
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Nano Banana for fast editing
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    // Extract image from response
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image generated in response.");
  } catch (error) {
    console.error("Error editing image:", error);
    throw error;
  }
};

/**
 * Composes a car image onto a background template using a fixed system instruction.
 * Uses Gemini 2.5 Flash Image.
 */
export const composeCarWithBackground = async (
  carImageBase64: string,
  carImageMimeType: string,
  templateImageBase64: string,
  templateImageMimeType: string,
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Nano Banana for composition
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: carImageMimeType,
              data: carImageBase64,
            },
          },
          {
            inlineData: {
              mimeType: templateImageMimeType,
              data: templateImageBase64,
            },
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT_BACKGROUND_COMPOSITION,
      },
    });

    // Extract image from response
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No se pudo generar la imagen compuesta.");
  } catch (error) {
    console.error("Error componiendo imagen de auto con fondo:", error);
    throw error;
  }
};

/**
 * Generate a new car image using Gemini 3 Pro Image Preview
 * Supports high resolution (4K) and aspect ratios.
 */
export const generateCarImage = async (
  prompt: string,
  aspectRatio: AspectRatio,
  imageSize: ImageSize
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // Pro model for high quality generation
      contents: {
        parts: [
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
          imageSize: imageSize
        }
      }
    });

    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image generated.");
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

/**
 * Analyze a car image using Gemini 3 Pro Preview
 * Returns structured text analysis.
 */
export const analyzeCarImage = async (
  base64Image: string,
  prompt: string,
  mimeType: string = "image/jpeg"
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Strong reasoning model for analysis
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    return response.text || "No se pudo generar el análisis.";
  } catch (error) {
    console.error("Error analyzing image:", error);
    throw error;
  }
};

