import { GoogleGenAI, Type } from "@google/genai";
import { AspectRatio, ImageSize } from "../types";

// Initialize Gemini Client
// We assume process.env.API_KEY is available in the environment
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// System prompt for background composition
const SYSTEM_PROMPT_BACKGROUND_COMPOSITION = `You will receive two images: a source image of a vehicle and a background studio template. Perform a photorealistic composition with these strict steps: 1) Extraction: Completely remove the original background from the vehicle image, isolating the car with clean edges. 2) Composition: Superimpose the isolated vehicle onto the provided studio template image. Do not alter the template's design, lighting, or text in any way. 3) Critical Scale: Adjust the vehicle's size to appear large and imposing, filling the central space of the room with bumpers nearing the lateral edges. It must not look small. 4) Realistic Integration: Generate a sharp, mirror-like reflection of the vehicle on the glossy floor matching its perspective, and add dark contact shadows under the tires to anchor it to the ground.`;


/**
 * Edit an image using Gemini 2.5 Flash Image (Nano Banana)
 * Perfect for adding shadows or modifying elements.
 */
export const editCarImage = async (
  base64Image: string, 
  prompt: string, 
  mimeType: string = "image/jpeg"
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Nano Banana for fast editing
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    // Extract image from response
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image generated in response.");
  } catch (error) {
    console.error("Error editing image:", error);
    throw error;
  }
};

/**
 * Composes a car image onto a background template using a fixed system instruction.
 * Uses Gemini 2.5 Flash Image.
 */
export const composeCarWithBackground = async (
  carImageBase64: string,
  carImageMimeType: string,
  templateImageBase64: string,
  templateImageMimeType: string,
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Nano Banana for composition
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: carImageMimeType,
              data: carImageBase64,
            },
          },
          {
            inlineData: {
              mimeType: templateImageMimeType,
              data: templateImageBase64,
            },
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT_BACKGROUND_COMPOSITION,
      },
    });

    // Extract image from response
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No se pudo generar la imagen compuesta.");
  } catch (error) {
    console.error("Error componiendo imagen de auto con fondo:", error);
    throw error;
  }
};

/**
 * Generate a new car image using Gemini 3 Pro Image Preview
 * Supports high resolution (4K) and aspect ratios.
 */
export const generateCarImage = async (
  prompt: string,
  aspectRatio: AspectRatio,
  imageSize: ImageSize
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // Pro model for high quality generation
      contents: {
        parts: [
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
          imageSize: imageSize
        }
      }
    });

    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image generated.");
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

/**
 * Analyze a car image using Gemini 3 Pro Preview
 * Returns structured text analysis.
 */
export const analyzeCarImage = async (
  base64Image: string,
  prompt: string,
  mimeType: string = "image/jpeg"
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Strong reasoning model for analysis
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image
            }
          },
